import React, { useEffect, useMemo, useState, useCallback } from 'react';
import { useTable } from 'react-table';
import AddLaborHours from './AddLaborHours.js';

const LaborHours = ({ apiBaseUrl }) => {
  const [laborhours, setLaborHours] = useState([]);

  const fetchAPI = useCallback(async (url, options = {}) => {
    const authToken = sessionStorage.getItem('authToken');
    const response = await fetch(url, {
      ...options,
      headers: {
        ...options.headers,
        'Authorization': `Bearer ${authToken}`,
        'Content-Type': 'application/json',
      },
    });
    if (!response.ok) {
      const errorResponse = await response.json();
      throw new Error(errorResponse.message || `Error fetching ${url}`);
    }
    return response.json();
  }, []);

  useEffect(() => {
    const fetchlaborhours = async () => {
      try {
        const data = await fetchAPI(`${apiBaseUrl}/laborhoursAPI`);
        setLaborHours(data);
      } catch (error) {
        console.error('Failed to fetch laborhours:', error);
      }
    };

    fetchlaborhours();
  }, [fetchAPI, apiBaseUrl]);

  const columns = useMemo(() => [
    {
      Header: 'Labor Hour ID',
      accessor: 'labid',
    },
    {
      Header: 'Employee ID',
      accessor: 'employeeid',
    },
    {
      Header: 'Project ID',
      accessor: 'projectid',
    },
    {
      Header: 'Start',
      accessor: 'start',
    },
    {
      Header: 'End',
      accessor: 'end',
    },
  ], []);

  const tableInstance = useTable({ columns, data: laborhours });

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    rows,
    prepareRow,
  } = tableInstance;

  return (
    <div>
      <h1>Labor Hours</h1>
      <AddLaborHours apiBaseUrl={apiBaseUrl} fetchAPI={fetchAPI} laborhours={laborhours}/>
      <table {...getTableProps()} style={{ border: 'solid 1px blue', width: '100%' }}>
        <thead>
          {headerGroups.map(headerGroup => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map(column => (
                <th {...column.getHeaderProps()} style={{ borderBottom: 'solid 3px red', background: 'aliceblue', color: 'black', fontWeight: 'bold', padding: '10px' }}>
                  {column.render('Header')}
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {rows.map((row) => {
            prepareRow(row);
            return (
              <tr {...row.getRowProps()}>
                {row.cells.map(cell => (
                  <td {...cell.getCellProps()} style={{ padding: '10px', border: 'solid 1px gray' }}>
                    {cell.render('Cell')}
                  </td>
                ))}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
};

export default LaborHours;
